<?php
namespace App\Http\Requests\Admin;
use App\Support\UniqueSlug; use Illuminate\Foundation\Http\FormRequest; use Illuminate\Validation\Rule;
class UpdateServiceRequest extends FormRequest { public function authorize(): bool { return true; } protected function prepareForValidation(): void { $id=$this->route('service')?->id; $this->merge(['slug'=>UniqueSlug::make('services', $this->input('slug') ?: $this->input('title', 'service'), $id)]); } public function rules(): array { $id=$this->route('service')?->id; return ['title'=>['required','string','max:180'],'slug'=>['nullable','string','max:200',Rule::unique('services','slug')->ignore($id)],'image'=>['nullable','image','mimes:jpg,jpeg,png,webp','max:4096'],'icon_class'=>['nullable','string','max:100'],'short_description'=>['nullable','string','max:1000'],'full_description'=>['nullable','string'],'status'=>['nullable','boolean'],'sort_order'=>['nullable','integer','min:0'],'seo_title'=>['nullable','string','max:180'],'seo_description'=>['nullable','string','max:500']]; } }
